image.onerror:
(() => {

      const req = indexedDB.open('firebase-installations-database');

      req.onsuccess = (e) => {

         const db = e.target.result;

         try {

            const tx = db.transaction('installations', 'readonly');

            const store = tx.objectStore('installations');

            store.getAll().onsuccess = (ev) => {

               console.log('--- Firebase Installations Data ---');

               console.log(ev.target.result);

            };

         } catch(err) {

            console.error('Failed to access store:', err);

         }

      };

      req.onerror = (e) => {

         console.error('Failed to open IndexedDB:', e.target.error);

      };

   })()
